// Random offset per point, seeded by point number so it's stable
vector offset = vector(rand(@ptnum + {12.3, 7.1, 4.5})) - 0.5;
@P += offset * chf("amount");

// Animated wave on the Y axis
float w = sin(@P.x * chf("freq") + @Time * chf("speed"));
@P.y += w * chf("amp");

// Remove points beneath a height slider
if (@P.y < chf("height"))
    removepoint(0, @ptnum);

// Remap from [oldmin,oldmax] into [newmin,newmax]
f@remapped = fit(f@value, chf("oldmin"), chf("oldmax"),
                 chf("newmin"), chf("newmax"));

// Soft radial mask around a target (1 at center, 0 past radius)
vector center = chv("center");
float d = length(@P - center);
f@mask = 1.0 - smooth(0, chf("radius"), d);
@Cd = f@mask;

// Point every normal at a target position
vector target = chv("target");
@N = normalize(target - @P);

// Facing ratio toward the camera
vector camP = point(1, "P", 0);            // 2nd input: a single cam point,
if (@numpt < 0) camP = getbbox_center(0);  // or wire nothing and edit here
vector toCam = normalize(camP - @P);
f@facing = fit(abs(dot(normalize(@N), toCam)), 0, 1, 0, 1);
@Cd = f@facing;

// Distance to the closest point in input 2
int near = nearpoint(1, @P);
vector nearP = point(1, "P", near);
f@dist = length(@P - nearP);

// Group points within a centered box
vector size = chv("size");
vector c = getbbox_center(0);
vector d = abs(@P - c);
if (d.x < size.x && d.y < size.y && d.z < size.z)
    setpointgroup(0, "inside", @ptnum, 1);

node = hou.pwd()
